texttool_globals_dialog_checkbox___homebusiness_popup_charging_possibility_checkbox_label = TextObject(bs_BA="Postoji mogućnost punjenja", cs_CZ="Možnost nabíjení", da_DK="Opladningsmulighed foreligger.", de_DE="Lademöglichkeit vorhanden", el_GR="Υπάρχει δυνατότητα φόρτισης", en_GB="Charging option available", es_ES="Opción de carga disponible", fi_FI="Latausmahdollisuus saatavilla", fr_FR="Possibilité de recharger disponible", hr_HR="Raspoloživa mogućnost punjenja", hu_HU="Töltési lehetőség elérhető", it_IT="Possibilità di ricarica disponibile", nl_NL="Laadmogelijkheid beschikbaar", no_NO="Det fins lademuligheter", pl_PL="Dostępna możliwość ładowania", pt_PT="Opção de carregamento disponível", ro_RO="Posibilitate de încărcare prezentă", ru_RU="Доступен вариант зарядки", sk_SK="K dispozícii je možnosť nabíjania", sl_SI="Možnost polnjenja", sr_RS="Postoji mogućnost punjenja", sv_SE="Laddningsmöjlighet finns", tr_TR="Şarj olanağı mevcut", uk_UA="Доступна можливість заряджання")
texttool_globals_dialog_message___avoided_charging_stations_message = TextObject(bs_BA="Pojedinačne stanice za punjenje se preko opcija za planiranje punjenja mogu\noznačiti za „Izbjegavati“. Na ovom popisu se navode sve izbjegnute stanice za\npunjenje i one se mogu ponovo ukloniti povlačenjem.", cs_CZ="Jednotlivé nabíjecí stanice lze v možnostech plánování nabíjení označit jako\n„Vyhnout se“. Všechny vyloučené nabíjecí stanice se zobrazí v tomto seznamu a lze\nje opět odstranit přejetím prstu.", da_DK="Enkelte ladestationer kan markeres som \"Undgået\" via optionerne for\nopladningsplanlægningen. Denne liste viser alle undgåede ladestationer, som kan\nfjernes igen ved at swipe.", de_DE="Einzelne Ladestationen können über die Optionen für die Ladeplanung als\n\"Gemieden\" markiert werden. In dieser Liste werden alle gemiedenen\nLadestationen aufgeführt und können durch Wischen wieder entfernt werden.", el_GR="Μεμονωμένοι σταθμοί φόρτισης μπορούν, μέσω των επιλογών, να επισημανθούν ως\n\"Να αποφεύγεται\". Σε αυτήν τη λίστα αναφέρονται όλοι οι σταθμοί φόρτισης που\nαποφεύγονται, και μπορούν να αφαιρεθούν πάλι με μια κίνηση σάρωσης με το\nδάχτυλο.", en_GB="You can mark individual charging stations as \"Avoided\" in the charging schedule\nsettings. This list contains all avoided charging stations and they can be removed\nagain by swiping.", es_ES="Algunas estaciones de carga se pueden marcar como \"Evitadas\" en las opciones del\nplan de carga. En esta lista aparecen todas las estaciones de carga que se han\nevitado y se pueden eliminar deslizando el dedo.", fi_FI="Yksittäisiä latausasemia voi merkitä \"vältettäviksi\" lataussuunnitelman asetuksista.\nTällä listalla näkyvät kaikki vältettävät latausasemat. Niitä voi poistaa listalta\npyyhkäisemällä.", fr_FR="Vous avez la possibilité d'éviter certaines bornes de recharge via les options de la\nplanification de la recharge. Cette liste contiendra alors toutes les bornes de charge\névitées que vous pouvez de nouveau supprimer de la liste en glissant votre doigt.", hr_HR="Pojedine stanice za punjenje mogu se preko opcija za planiranje punjenja označiti za\n\"izbjegavanje\". Na tom se popisu navode sve izbjegavane stanice za punjenje i mogu\nse povlačenjem prstom ponovno ukloniti.", hu_HU="Az egyes töltőállomások a töltéstervezési beállításokon keresztül „Elkerülve”\njelölhetők. Az összes elkerült töltőállomás megjelenik ebben a listában, és a\nkezedet elhúzva ismét eltávolítható.", it_IT="Le singole stazioni di ricarica possono essere contrassegnate come \"evitate\" tramite\nle opzioni di pianificazione della ricarica. Tutte le stazioni di ricarica evitate vengono\nvisualizzate in questo elenco e possono essere nuovamente rimosse scorrendo con\nil dito.", nl_NL="Individuele laadstations kunnen via de opties voor laadplanning als \"Vermijden\"\nworden gemarkeerd. In deze lijst worden alle gemeden laadstations vermeld en ze\nkunnen worden verwijderd door een veegbeweging.", no_NO="Enkelte ladestasjoner kan merkes med «Unngå» i alternativene for\nladeplanleggingen. Alle ladestasjoner som unngås, legges i denne listen. Du kan\nsveipe for å fjerne dem igjen.", pl_PL="Poszczególne stacje ładowania można oznaczyć jako „Unikane” za pomocą opcji\nplanowania ładowania. Wszystkie unikane stacje ładowania są wyświetlane na tej\nliście i można je ponownie usunąć, przesuwając palcem.", pt_PT="É possível marcar estações de carregamento como \"A evitar\" através das opções\npara planeamento do carregamento. Nesta lista são introduzidas todas as estações\nde carregamento a evitar e através do varrimento podem voltar a ser removidas.", ro_RO="Staţiile de încărcare individuale pot fi marcate ca \"Evitate\" în opţiunile pentru\nplanificarea încărcării. În această listă sunt incluse toate staţiile de încărcare\nevitate, care pot fi eliminate din nou prin glisare.", ru_RU="Отдельные зарядные станции можно пометить как «Избегаемые» с помощью\nопций планирования зарядки. Все избегаемые зарядные станции отображаются\nв этом списке, и их можно снова удалить, проведя пальцем по экрану.", sk_SK="Jednotlivé nabíjacie stanice sa môžu v možnostiach plánovania nabíjania označiť\nako “Vynechať“. V tomto zozname sa zobrazia všetky vynechané nabíjacie stanice a\nmôžu sa znovu odstrániť potiahnutím.", sl_SI="Posamezne polnilne postaje je med možnostmi za načrtovanje polnjenja mogoče\noznačiti z oznako \"Izogibanje\". Na tem seznamu so navedene vse polnilne postaje,\nki se jim želite izogniti. S potegom prsta jih lahko odstranite s seznama.", sr_RS="Pojedine stanice za punjenje mogu da se označe kao „Izbegavati“ preko opcija za\nplaniranje punjenja. Na ovom spisku su navedene sve stanice za punjenje koje treba\nizbegavati i iste se mogu ponovo ukloniti povlačenjem.", sv_SE="Enskilda laddstationer kan markeras som ”Undvik” i alternativen för\nladdningsplanering. I denna lista visas alla laddstationer som undviks. De kan tas\nbort genom att svepa.", tr_TR="Münferit şarj istasyonları şarj planlaması seçenekleri üzerinden \"kaçınılan\" olarak\nişaretlenebilir. Bu listede tüm kaçınılan şarj istasyonları listelenir ve silme hareketi\nile tekrar kaldırılabilir.", uk_UA="Окремі зарядні станції можна позначити як «Слід уникати» за допомогою опцій\nпланування зарядки. Усі зарядні станції, яких уникають, відображаються в цьому\nсписку, і їх можна знову видалити, провівши пальцем по екрану.")
texttool_globals_dialog_message___charging_adapter_availability_info_message = TextObject(bs_BA="Ukoliko posjedujete odgovarajući adapter, možete koristiti NACS stanice za\npunjenje. U tom slučaju se stanice za punjenje s odgovarajućim priključkom uzimaju\nu obzir prilikom planiranja rute. Snaga punjenja i trajanje punjenja na stanicama za\npunjenje s adapterom mogu odstupati.", cs_CZ="Pokud máte vhodný adaptér, můžete používat nabíjecí stanice NACS. Nabíjecí\nstanice s odpovídajícím připojením se pak zohlední při plánování trasy. Nabíjecí\nvýkon a doba nabíjení na nabíjecích stanicích s adaptéry se mohou lišit.", da_DK="Hvis du har en passende adapter, kan du anvende NACS-ladestationer. Så tages der\nhøjde for ladestationer med tilsvarende tilslutning i ruteplanneren. Ladeeffekt og\nopladningstid på ladestationer med adapter kan afvige.", de_DE="Wenn du über einen entsprechenden Adapter verfügst, kannst du\nNACS-Ladestationen nutzen. Ladestationen mit entsprechendem Anschluss werden\ndann in der Routenplanung berücksichtigt. Ladeleistung und Ladedauer an\nLadestationen mit Adapter können abweichen.", el_GR="Εάν διαθέτετε τον κατάλληλο αντάπτορα, μπορείτε να χρησιμοποιήσετε σταθμούς\nφόρτισης NACS. Οι σταθμοί φόρτισης με αντίστοιχη υποδοχή σύνδεσης λαμβάνονται\nτότε υπόψη στον σχεδιασμό διαδρομής. Η ισχύς φόρτισης και η διάρκεια φόρτισης σε\nσταθμούς φόρτισης με αντάπτορες ενδέχεται να διαφέρουν.", en_GB="If you have a suitable adapter, you can use NACS charging stations. Charging\nstations with a suitable connection are then taken into account when planning the\nroute. The charging capacity and charging duration at charging stations with\nadapter may vary.", es_ES="Si dispone de un adaptador adecuado, podrá utilizar estaciones de carga NACS. Las\nestaciones de carga con una conexión correspondiente se tienen en cuenta en la\nplanificación de la ruta. La potencia y la duración de la carga pueden variar en las\nestaciones con adaptador.", fi_FI="Jos sinulla on asianmukainen sovitin, voit käyttää NACS-latausasemia. Vastaavalla\nliitännällä varustetut latausasemat huomioidaan tällöin reittisuunnittelussa.\nLatausteho ja latauksen kesto latausasemilla sovittimen kanssa voivat vaihdella.", fr_FR="Si vous disposez d'un adaptateur approprié, vous pouvez utiliser des bornes de\nrecharge NACS. Les bornes de recharge équipées du raccordement correspondant\nsont alors prises en compte dans la planification de l'itinéraire. La puissance de\nrecharge et la durée de recharge sur les bornes de recharge avec adaptateur\npeuvent différer.", hr_HR="Ako raspolažete odgovarajućim adapterom, možete koristiti NACS stanice za\npunjenje. U planiranju rute uzeti će se u obzir stanice za punjenje s odgovarajućim\npriključkom. Snaga i vrijeme punjenja na stanicama s adapterom mogu odstupati.", hu_HU="Ha rendelkezel megfelelő adapterrel, használhatod az NACS töltőállomásokat. A\nmegfelelő csatlakozással rendelkező töltőállomásokat ezután az útvonaltervezés\nsorán figyelembe veszi a rendszer. Az adapterrel rendelkező töltőállomások\ntöltőteljesítménye és töltési ideje eltérő lehet.", it_IT="Se si dispone di un apposito adattatore, è possibile utilizzare le stazioni di ricarica\nNACS. Le stazioni di ricarica con un attacco corrispondente verranno quindi prese in\nconsiderazione nella pianificazione dell'itinerario. La potenza e il tempo di ricarica\ndelle stazioni di ricarica con adattatore possono variare.", nl_NL="Als je over een geschikte adapter beschikt, kun je NACS-laadstations gebruiken.\nLaadstations met een bijbehorende aansluiting worden dan meegenomen in de\nrouteplanning. Het laadvermogen en de laadtijd bij laadstations met adapters\nkunnen variëren.", no_NO="Hvis du har en passende adapter, kan du bruke NACS-ladestasjoner. Da inkluderes\ndisse ladestasjonene i ruteplanleggingen. Ladeeffekten og ladetiden kan avvike på\nladestasjoner med adapter.", pl_PL="Jeśli posiadasz odpowiedni adapter, możesz korzystać ze stacji ładowania NACS.\nStacje ładowania z odpowiednim złączem są wówczas uwzględniane przy\nplanowaniu trasy. Moc ładowania i czas ładowania na stacjach ładowania z\nadapterami mogą być inne.", pt_PT="Caso disponhas de um adaptador adequado podes utilizar estações de carga NACS.\nAs estações de carga com a correspondente ligação são depois consideradas no\nplaneamento do trajeto. A potência de carga e a duração do carregamento nas\nestações de carregamento com adaptador podem variar.", ro_RO="Dacă dispuneţi de un adaptor corespunzător, puteţi utiliza staţii de încărcare NACS.\nStaţiile de încărcare cu priză corespunzătoare vor fi luate în acest caz în considerare\nîn planificarea traseului. Puterea şi durata de încărcare la staţiile de încărcare cu\nadaptor pot diferi.", ru_RU="Если у вас есть соответствующий адаптер, вы можете использовать зарядные\nстанции NACS. Зарядные станции с соответствующим подключением\nучитываются при планировании маршрута. Мощность зарядки и время зарядки\nна зарядных станциях с адаптерами могут отличаться.", sk_SK="Ak máte príslušný adaptér, môžete používať nabíjacie stanice NACS. Nabíjacie\nstanice s príslušným pripojením sa potom zohľadnia pri plánovaní trasy. Nabíjací\nvýkon a čas nabíjania na nabíjacích staniciach s adaptérmi sa môžu líšiť.", sl_SI="Če imate ustrezen adapter, lahko uporabljate polnilne postaje NACS. Polnilne\npostaje z ustreznim priključkom se nato upoštevajo pri načrtovanju poti. Moč in čas\npolnjenja na polnilnih postajah z adapterjem se lahko razlikujeta.", sr_RS="Ako posedujete odgovarajući adapter, možete da koristite NACS stanice za punjenje.\nU tom slučaju će, tokom planiranja rute, biti uzete u obzir stanice za punjenje sa\nodgovarajućim priključkom. Kapacitet punjenja i trajanje punjenja na stanicama za\npunjenje sa adapterom mogu da odstupaju.", sv_SE="Om du har motsvarande adapter kan du använda NACS-laddstationer.\nLaddstationer med motsvarande anslutning beaktas då i ruttplaneringen.\nLaddeffekten och laddtiden kan variera på laddstationer med adapter.", tr_TR="Eğer uygun bir adaptörün varsa NACS şarj istasyonlarını kullanabilirsin. Uygun\nbağlantılara sahip şarj istasyonları daha sonra rota planlamasında dikkate alınır.\nAdaptörlü şarj istasyonlarında şarj gücü ve şarj süresi farklılık gösterebilir.", uk_UA="Якщо у вас є відповідний адаптер, ви можете використовувати зарядні станції\nNACS. Зарядні станції з відповідним підключенням враховуються при плануванні\nмаршруту. Потужність зарядки та час зарядки на зарядних станціях з адаптерами\nможуть відрізнятися.")
texttool_globals_dialog_message___charging_adapter_ccs_availability_info_message = TextObject(bs_BA="Ukoliko posjedujete odgovarajući adapter, možete koristiti CCS stanice za punjenje.\nU tom slučaju se stanice za punjenje s odgovarajućim priključkom uzimaju u obzir\nprilikom planiranja rute. Snaga punjenja i trajanje punjenja mogu odstupati na\nstanicama za punjenje s adapterom.", cs_CZ="Pokud máte vhodný adaptér, můžete používat nabíjecí stanice CCS. Nabíjecí stanice\ns příslušným připojením se pak zohlední při plánování trasy. Nabíjecí výkon a doba\nnabíjení na nabíjecích stanicích s adaptérem se mohou lišit.", da_DK="Hvis du har en passende adapter, kan du anvende CCS-ladestationer. Så tages der\nhøjde for ladestationer med tilsvarende tilslutning i ruteplanneren. Ladeeffekt og\nopladningstid på ladestationer med adapter kan afvige.", de_DE="Wenn du über einen entsprechenden Adapter verfügst, kannst du\nCCS-Ladestationen nutzen. Ladestationen mit entsprechendem Anschluss werden\ndann in der Routenplanung berücksichtigt. Ladeleistung und Ladedauer an\nLadestationen mit Adapter können abweichen.", el_GR="Εάν διαθέτετε τον αντίστοιχο αντάπτορα, μπορείτε να χρησιμοποιείτε σταθμούς\nφόρτισης CCS. Σε αυτήν την περίπτωση κατά τον σχεδιασμό διαδρομής λαμβάνονται\nυπόψη οι σταθμοί φόρτισης με την εν λόγω σύνδεση. Η ισχύς φόρτισης και η\nδιάρκεια φόρτισης ενδέχεται να διαφέρουν σε σταθμούς φόρτισης με αντάπτορα.", en_GB="You can use CCS charging stations if you have the correct adapter. Charging stations\nwith the correct connectors will then be considered when planning the route. The\ncharging power and duration may vary at charging stations that require the use of\nan adapter.", es_ES="Si dispone de un adaptador adecuado, podrá utilizar estaciones de carga CCS. Las\nestaciones de carga con una conexión correspondiente se tienen en cuenta en la\nplanificación de la ruta. La potencia y la duración de la carga pueden variar en las\nestaciones con adaptador.", fi_FI="Jos sinulla on asianmukainen sovitin, voit käyttää CCS-latausasemia. Vastaavalla\nliitännällä varustetut latausasemat huomioidaan tällöin reittisuunnittelussa.\nLatausteho ja latauksen kesto latausasemilla sovittimen kanssa voivat vaihdella.", fr_FR="Si vous disposez d'un adaptateur approprié, vous pouvez utiliser des bornes de\nrecharge CCS. Les bornes de recharge équipées du raccord correspondant sont alors\nprises en compte dans la planification de l'itinéraire. La puissance de recharge et la\ndurée de recharge sur les bornes de recharge avec adaptateur peuvent différer.", hr_HR="Ako raspolažete odgovarajućim adapterom, možete koristiti CCS stanice za\npunjenje. Stanice za punjenje s odgovarajućim priključkom tada se uzimaju u obzir\nkod planiranja rute. Snaga i dužina trajanja punjenja mogu odstupati na stanicama\nza punjenje s adapterom.", hu_HU="Ha rendelkezel megfelelő adapterrel, használhatod a CCS töltőállomásokat. A\nmegfelelő csatlakozóval rendelkező töltőállomásokat ezután figyelembe veszi az\nútvonaltervezés. Az adapterrel rendelkező töltőállomásokon a töltési teljesítmény\nés a töltési idő eltérő lehet.", it_IT="Se si dispone di un apposito adattatore, è possibile utilizzare le stazioni di ricarica\nCCS. Le stazioni di ricarica con un attacco corrispondente verranno quindi prese in\nconsiderazione nella pianificazione dell'itinerario. La potenza e il tempo di ricarica\ndelle stazioni di ricarica con adattatore possono variare.", nl_NL="Als je over de juiste adapter beschikt, kun je CCS-laadstations gebruiken.\nLaadstations met deze aansluiting worden dan in de routeplanning in acht\ngenomen. Laadvermogen en laadduur op laadstations met adapter kunnen\nafwijken.", no_NO="Hvis du har en passende adapter, kan du bruke CCS-ladestasjoner. Da inkluderes\ndisse ladestasjonene i ruteplanleggingen. Ladeeffekten og ladetiden kan avvike på\nladestasjoner med adapter.", pl_PL="Jeśli posiadasz odpowiedni adapter, możesz korzystać ze stacji ładowania CCS.\nStacje ładowania z odpowiednim złączem są wówczas uwzględniane przy\nplanowaniu trasy. Moc ładowania i czas ładowania na stacjach ładowania z\nadapterami mogą być inne.", pt_PT="Caso disponhas do respetivo adaptador, podes utilizar as estações de carregamento\nCCS. As estações de carregamento com a respetiva ligação são depois consideradas\nno planeamento de trajeto. A potência de carregamento e a duração de\ncarregamento nas estações de carregamento com adaptador podem apresentar\ndivergências.", ro_RO="Dacă dispuneţi de un adaptor corespunzător, puteţi utiliza staţii de încărcare CCS.\nStaţiile de încărcare cu priză corespunzătoare vor fi luate în acest caz în considerare\nîn planificarea traseului. Puterea şi durata de încărcare la staţiile de încărcare cu\nadaptor pot diferi.", ru_RU="Если у вас есть соответствующий адаптер, вы можете использовать зарядные\nстанции CCS. Зарядные станции с соответствующим подключением учитываются\nпри планировании маршрута. Мощность зарядки и время зарядки на зарядных\nстанциях с адаптером могут отличаться.", sk_SK="Ak máte príslušný adaptér, môžete používať nabíjacie stanice CCS. Nabíjacie stanice\ns príslušným pripojením sa potom zohľadnia pri plánovaní trasy. Nabíjací výkon a\ndoba nabíjania na nabíjacích staniciach s adaptérmi sa môžu líšiť.", sl_SI="Če imate ustrezen adapter, lahko uporabljate polnilne postaje CCS. Polnilne postaje\nz ustreznim priključkom se nato upoštevajo pri načrtovanju poti. Moč in čas\npolnjenja na polnilnih postajah z adapterjem se lahko razlikujeta.", sr_RS="Ako raspolažete odgovarajućim adapterom, možete da koristite CCS stanice za\npunjenje. U tom slučaju će se prilikom planiranja rute uvažiti stanice za punjenje sa\nodgovarajućim priključkom. Snaga punjenja i trajanje punjenja na stanicama za\npunjenje s adapterom mogu da odstupaju.", sv_SE="Om du har en motsvarande adapter kan du använda CCS-laddstationer.\nLaddstationer med motsvarande anslutning beaktas då i ruttplaneraren.\nLaddeffekten och laddningstiderna på laddstationer med adapter kan variera.", tr_TR="Eğer uygun bir adaptörün varsa CCS şarj istasyonlarını kullanabilirsin. Uygun\nbağlantılara sahip şarj istasyonları daha sonra rota planlamasında dikkate alınır.\nAdaptörlü şarj istasyonlarında şarj gücü ve şarj süresi farklılık gösterebilir.", uk_UA="Якщо у вас є відповідний адаптер, ви можете використовувати зарядні станції\nCCS. Зарядні станції з відповідним підключенням враховуються при плануванні\nмаршруту. Потужність зарядки та час зарядки на зарядних станціях з адаптером\nможуть відрізнятися.")
texttool_globals_dialog_message___charging_point_operators_message = TextObject(bs_BA="Za planiranje punjenja se prednost može dati određenim ponuđačima stanica za\npunjenje. Ukoliko se neki ponuđač ne pojavljuje na popisu, isti se može dodati preko\nopcija.", cs_CZ="Určití poskytovatelé nabíjecích stanic mohou být při plánování nabíjení\nupřednostněni. Pokud se poskytovatel v seznamu neobjeví, lze jej přidat\nprostřednictvím možností.", da_DK="Det er muligt at foretrække bestemte ladestationsudbydere til\nopladningsplanlægningen. Hvis en udbyder ikke bliver vist på listen, kan den tilføjes\nvia optionerne.", de_DE="Bestimmte Ladestationsanbieter können für die Ladeplanung bevorzugt werden.\nFalls ein Anbieter nicht in der Liste erscheint, kann dieser über die Optionen\nhinzugefügt werden.", el_GR="Για τον προγραμματισμό φόρτισης υπάρχει η δυνατότητα να προτιμώνται\nσυγκεκριμένοι πάροχοι σταθμών φόρτισης. Εάν ένας πάροχος δεν εμφανίζεται στη\nλίστα, μπορεί να προστεθεί μέσω των επιλογών.", en_GB="Certain charging station providers can be preferred for scheduled charging. You can\nadd providers via the options if a provider is not shown in the list.", es_ES="Algunos proveedores de estaciones de carga se pueden priorizar para el plan de\ncarga. Si un proveedor no aparece en la lista, se puede añadir en las opciones.", fi_FI="Lataussuunnitelmassa voidaan suosia tiettyjä latausasemien ylläpitäjiä. Jos jokin\nniistä ei näy listalla, se voidaan lisätä asetuksista.", fr_FR="Certains fournisseurs de bornes de recharge peuvent être privilégiés pour la\nplanification de la recharge. Si un fournisseur n'apparaît pas dans la liste, il peut\nêtre ajouté via les options.", hr_HR="Određeni operateri stanica za punjenje mogu se preferirati kod planiranja punjenja.\nAko se operater ne pojavljuje na popisu, moguće ga je dodati u opcijama.", hu_HU="Bizonyos töltőállomás-szolgáltatókat preferáltként lehet kezelni a töltés\ntervezésénél. Ha egy szolgáltató nem jelenik meg a listán, az opciók segítségével\nhozzáadható.", it_IT="Alcuni operatori di stazioni di ricarica possono avere la priorità per la pianificazione\ndella ricarica. Se un operatore non compare nell'elenco, è possibile aggiungerlo\ntramite le opzioni.", nl_NL="Aan bepaalde laadstationaanbieders kan de voorkeur worden gegeven voor de\nlaadplanning. Als een aanbieder niet voorkomt in de lijst, kan deze via de opties\nworden toegevoegd.", no_NO="Du kan foretrekke bestemte ladestasjonsoperatører for ladeplanleggingen. Hvis en\noperatør ikke vises på listen, kan du legge den til i alternativene.", pl_PL="Niektórym operatorom stacji ładowania można nadać priorytet w planowaniu\nładowania. Jeśli operatora nie ma na liście, można go dodać za pomocą opcji.", pt_PT="Determinados fornecedores de estações de carregamento podem ser preferidos no\nplaneamento de trajeto. Caso um fornecedor não seja apresentado na lista, este\npode ser adicionado através das opções.", ro_RO="Pentru planificarea încărcării este posibilă favorizarea anumitor operatori de staţii\nde încărcare. În cazul în care un operator nu apare în listă, acesta poate fi adăugat\nprin intermediul opţiunilor.", ru_RU="Некоторые операторы зарядных станций могут быть приоритетными для\nпланирования зарядки. Если оператор не отображается в списке, его можно\nдобавить с помощью опций.", sk_SK="Určití poskytovatelia nabíjacích staníc sa môžu uprednostniť pri plánovaní nabíjania.\nV prípade, že sa poskytovateľ nezobrazuje v zozname, môže sa pridať pomocou\nmožností.", sl_SI="Določenim ponudnikom polnilnih postaj lahko date prednost pri načrtovanju\npolnjenja. Če ponudnik ni na seznamu, ga lahko dodate med možnostmi.", sr_RS="Određenim ponuđačima stanica za punjenje se može dati prednost za planiranje\nruta. Ako se neki ponuđač ne prikazuje na spisku, onda se isti može dodati preko\nopcija.", sv_SE="Vissa laddstationsoperatörer kan prioriteras i laddningsplaneringen. Om en\noperatör inte visas i listan kan den läggas till i alternativen.", tr_TR="Belirli şarj istasyonu sağlayıcıları şarj planlaması için tercih edilebilir. Şayet bir\nsağlayıcı listede belirmiyorsa, seçenekler üzerinden eklenebilir.", uk_UA="Певні оператори зарядних станцій можуть бути пріоритетними для планування\nзарядки. Якщо оператора немає у списку, його можна додати за допомогою\nопцій.")
texttool_globals_dialog_message___confirm_tour_plan_changes = TextObject(bs_BA="Da li zaista želite preuzeti ove promjene?", cs_CZ="Chcete opravdu převzít tyto změny?", da_DK="Vil du virkelig overtage disse ændringer?", de_DE="Möchtest du diese Änderungen wirklich übernehmen?", el_GR="Θέλετε σίγουρα να υιοθετήσετε αυτές τις αλλαγές;", en_GB="Do you really want to apply these changes?", es_ES="¿Realmente desea aplicar estos cambios?", fi_FI="Haluatko varmasti ottaa nämä muutokset käyttöön?", fr_FR="Souhaitez-vous vraiment reprendre ces modifications?", hr_HR="Želite li uistinu preuzeti izmjene?", hu_HU="Biztosan át szeretnéd venni ezeket a módosításokat?", it_IT="Desidera applicare queste modifiche?", nl_NL="Weet je zeker dat je deze veranderingen wilt toepassen?", no_NO="Er du sikker på at du vil bruke disse endringene?", pl_PL="Czy na pewno chcesz zastosować te zmiany?", pt_PT="Queres mesmo assumir estas alterações?", ro_RO="Doriţi într-adevăr să preluaţi aceste modificări?", ru_RU="Вы действительно хотите применить эти изменения?", sk_SK="Skutočne chcete prebrať tieto zmeny?", sl_SI="Ali res želite prevzeti te spremembe?", sr_RS="Da li zaista želite da preuzmete ove izmene?", sv_SE="Är du säker på att du vill utföra dessa ändringar?", tr_TR="Bu değişiklikleri gerçekten devralmak istiyor musun?", uk_UA="Ви дійсно хочете застосувати ці зміни?")
texttool_globals_dialog_message___database_update_failed_message = TextObject(bs_BA="Aktualizacija karata je prekinuta. Provjerite da li je USB memorija uklonjena ili je\ninstaliranje bilo neuspješno.", cs_CZ="Update map byl přerušen. Zkontrolujte prosím, zda nebyl odstraněn USB stick nebo\nzda se instalace nezdařila.", da_DK="Kortopdatering blev afbrudt. Kontroller, om USB-nøglen blev fjernet, eller\ninstallationen mislykkedes.", de_DE="Das Kartenupdate wurde abgebrochen. Bitte prüfe, ob der USB-Stick entfernt wurde\noder die Installation fehlgeschlagen ist.", el_GR="Η ενημέρωση χαρτών διακόπηκε. Ελέγξτε, αν αφαιρέθηκε το USB stick ή απέτυχε η\nεγκατάσταση.", en_GB="The map update has been aborted. Please check whether the USB stick has been\nremoved or the installation has failed.", es_ES="La actualización del mapa se ha cancelado. Compruebe si se ha retirado la memoria\nUSB o si ha fallado la instalación.", fi_FI="Karttapäivitys on keskeytynyt. Tarkasta, onko USB-tikku poistettu tai asennus\nepäonnistunut.", fr_FR="La mise à jour des cartes a été annulée. Veuillez vérifier si la clé USB a été retirée ou\nsi l'installation a échoué.", hr_HR="Update karti je prekinut. Provjerite je li USB stick uklonjen ili instalacija nije uspjela.", hu_HU="A térképfrissítés megszakadt. Ellenőrizd, hogy eltávolításra került-e az\nUSB-pendrive, vagy sikertelen volt-e a telepítés.", it_IT="L'update cartine è stato interrotto. Controllare se la chiavetta USB è stata rimossa o\nse l'installazione non è riuscita.", nl_NL="De kaartupdate is geannuleerd. Controleer alsjeblieft of de USB-stick verwijderd\nwerd of de installatie is mislukt.", no_NO="Kartoppdatering avbrutt. Kontroller om USB-minnepinnen er fjernet eller\ninstalleringen mislyktes.", pl_PL="Aktualizacja map została przerwana. Proszę sprawdzić, czy została odłączona\npamięć USB , czy też instalowanie nie udało się.", pt_PT="A atualização do mapa foi interrompido. Por favor, verifica se a pen USB foi retirada\nou se a instalação falhou.", ro_RO="Actualizarea hărţii a fost întreruptă. Verificaţi dacă stickul USB a fost scos sau dacă\na eşuat instalarea.", ru_RU="Обновление карт прервано. Проверьте, не был ли удален USB-накопитель или\nже не удалось выполнить инсталляцию.", sk_SK="Aktualizácia mapy sa zrušila. Prosím skontrolujte, či nebol USB kľúč odstránený\nalebo sa nepodarila inštalácia.", sl_SI="Posodobitev kartografskega gradiva je bila prekinjena. Preverite, ali je bil USB-ključ\nodstranjen ali namestitev ni uspela.", sr_RS="Ažuriranje karata je prekinuto. Proverite da li je uklonjen USB stik ili je instalacija\nbila neuspešna.", sv_SE="Kartuppdateringen har avbrutits. Kontrollera om USB-minnet har tagits bort eller\ninstallationen misslyckades.", tr_TR="Harita güncellemesi iptal edildi. Lütfen USB belleğin çıkarılıp çıkarılmadığını veya\nkurulumun başarısız olup olmadığını kontrol et.", uk_UA="Оновлення карт перервано. Перевірте, чи не було видалено USB-накопичувач\nабо чи не вдалося виконати інсталяцію.")
texttool_globals_dialog_message___dialog_content_no_ev_route_found = TextObject(bs_BA="Nije moguće doći do cilja i e-tron planer rute nije mogao pronaći stanice za\npunjenje. Zatvaranjem ovog prozora se deaktivira e-tron planer ruta.", cs_CZ="Cíle nelze dosáhnout a plánovač tras e-tron nenalezl žádné nabíjecí stanice.\nZavřením tohoto okna se plánovač tras e-tron deaktivuje.", da_DK="Destination kan ikke nås, og e-tron-ruteplanner kunne ikke finde ladestationer.\ne-tron-ruteplanner deaktiveres ved at lukke dette vindue.", de_DE="Das Ziel kann nicht erreicht werden und der e-tron Routenplaner konnte keine\nLadestationen finden. Durch das Schließen dieses Fensters wird der e-tron\nRoutenplaner deaktiviert.", el_GR="Δεν είναι εφικτή η άφιξη στον προορισμό και ο σχεδιαστής διαδρομών e-tron δεν\nμπόρεσε να βρει σταθμούς φόρτισης. Κλείνοντας αυτό το παράθυρο,\nαπενεργοποιείται ο σχεδιαστής διαδρομών e-tron.", en_GB="The destination cannot be reached and the e-tron route planner could not find any\ncharging stations. Closing this window will deactivate the e-tron route planner.", es_ES="No se puede llegar al destino y el planificador de rutas e-tron no ha encontrado\nninguna estación de carga. Cerrando esta ventana se desactiva el planificador de\nrutas e-tron.", fi_FI="Kohdetta ei pystytä saavuttamaan eikä e-tron-reittiopas löytänyt latausasemia. Kun\ntämä ikkuna suljetaan, e-tron-reittiopas deaktivoituu.", fr_FR="La destination ne peut pas être atteinte et le planificateur d'itinéraire e-tron n'a pu\ntrouver aucune borne de recharge. Le planificateur d'itinéraire e-tron sera désactivé\nà la fermeture de cette fenêtre.", hr_HR="Nije moguće doći do odredišta i e-tron planer ruta nije pronašao stanice za\npunjenje. Zatvaranjem ovog prozorčića e-tron planer ruta će se zatvoriti.", hu_HU="Az úti cél nem érhető el, és az e-tron útvonaltervező nem talált töltőállomást.\nEnnek az ablaknak a bezárásával az e-tron útvonaltervező kikapcsol.", it_IT="Non è possibile raggiungere la destinazione e la pianificazione itinerario e-tron non\nha trovato stazioni di ricarica. Chiudendo questa finestra verrà disattivata la\npianificazione itinerario e-tron.", nl_NL="Het doel kan niet worden bereikt en de e-tron routeplanner kan geen laadstation\nvinden. Door dit venster te sluiten, wordt de e-tron routeplanner gedeactiveerd.", no_NO="Målet kan ikke nås, og e-tron-ruteplanleggeren finner ingen ladestasjoner. Hvis du\nlukker dette vinduet, deaktiveres e-tron-ruteplanleggeren.", pl_PL="Nie można dotrzeć do celu, a planowanie trasy e-tron nie znalazło stacji ładowania.\nZamknięcie tego okna wyłączy planowanie trasy e-tron.", pt_PT="Não é possível chegar ao destino e o planeamento do trajeto e-tron não consegue\nencontrar estações de carregamento. Ao fechar esta janela o planeamernto do\ntrajeto e-tron será desativado.", ro_RO="Destinaţia nu poate fi atinsă şi planificatorul de trasee e-tron nu a putut găsi nicio\nstaţie de încărcare. Prin închiderea ferestrei se va dezactiva planificatorul de trasee\ne-tron.", ru_RU="Цель не может быть достигнута, и планировщик маршрута e-tron не смог найти\nни одной зарядной станции. Закрытие этого окна деактивирует планировщик\nмаршрута e-tron.", sk_SK="Cieľ nie je možné dosiahnuť a plánovač trás e-tron nenašiel žiadne nabíjacie stanice.\nProstredníctvom zatvorenia tohto okna sa deaktivuje plánovač trás e-tron.", sl_SI="Cilja ni mogoče doseči in načrtovalnik poti e-tron ni našel nobene polnilne postaje.\nČe zaprete to okno, se bo načrtovalnik poti e-tron deaktiviral.", sr_RS="Cilj ne može da se dostigne i e-tron planer ruta nije mogao da pronađe stanice za\npunjenje. Zatvaranjem ovog prozora se deaktivira e-tron planer ruta.", sv_SE="Resmålet kan inte nås och e-trons ruttplanerare kunde inte hitta några\nladdstationer. Genom att stänga detta fönster avaktiveras e-trons ruttplanerare.", tr_TR="Hedefe ulaşılamıyor ve e-tron rota planlayıcı hiçbir şarj istasyonu bulamadı. Bu\npencerenin kapatılması ile e-tron rota planlayıcı devre dışı bırakılır.", uk_UA="Пункт призначення не може бути досягнутий, і планувальник маршруту e-tron не\nзміг знайти жодної зарядної станції. Закриття цього вікна деактивує\nпланувальник маршруту e-tron.")
texttool_globals_dialog_message___ev_trip_planner_info = TextObject(bs_BA="Podešena gornja granica punjenja u meniju vozila neće biti uvažena za planirana\nzaustavljanja zbog punjenja u okviru navigacije.", cs_CZ="Nastavená horní mez nabití v nabídce vozidla se pro naplánované zastávky pro\nnabíjení v rámci navigace nezohlední.", da_DK="Der tages ikke højde for den indstillede øvre ladegrænse i bilmenuen for de\nplanlagte ladestop i navigationen.", de_DE="Die eingestellte Ladeobergrenze im Fahrzeugmenü wird für die eingeplanten\nLadestopps innerhalb der Navigation nicht berücksichtigt.", el_GR="Το ρυθμισμένο ανώτατο όριο φόρτισης στο μενού οχήματος δεν λαμβάνεται υπόψη\nγια τις προγραμματισμένες στάσεις φόρτισης εντός της πλοήγησης.", en_GB="The upper charging limit set in the Car menu will not be taken into account for the\ncharging stops planned in the navigation system.", es_ES="El límite superior de carga ajustado en el menú del vehículo no se tiene en cuenta\npara las paradas para cargar planificadas dentro de la navegación.", fi_FI="Auton valikossa asetettua latauksen ylärajaa ei huomioida suunnitelluissa\nlatauspysähdyksissä navigoinnin aikana.", fr_FR="Aux arrêts prévus dans la navigation pour la recharge, le système ne tiendra pas\ncompte de la limite de recharge supérieure réglée dans le menu du véhicule.", hr_HR="Namještena gornja granica punjenja u izborniku vozila neće se uzeti u obzir kod\nplaniranih zaustavljanja radi punjenja u sklopu navigacije.", hu_HU="A járműmenüben beállított felső töltési határ nem kerül figyelembevételre a\nbetervezett töltési megállásokhoz a navigáción belül.", it_IT="Il limite massimo di ricarica impostato nel menu della vettura non viene\nconsiderato per le soste di ricarica programmate all'interno della navigazione.", nl_NL="De ingestelde bovengrens voor opladen in het voertuigmenu wordt niet voor de\ngeplande laadstop binnen de navigatie in acht genomen.", no_NO="Det tas ikke hensyn til den øvre ladegrensen som er stilt inn i bilmenyen, på\nladestoppene som er planlagt i navigasjonen.", pl_PL="Ustawiona w menu pojazdu górna granica ładowania nie będzie uwzględniana w\nplanowaniu w nawigacji przystanków na ładowanie.", pt_PT="O limite superior de carga selecionado no menu do veículo não será considerado\npara as paragens para carregamento planeadas no âmbito da navegação.", ro_RO="Limita superioară de încărcare setată în meniul autovehiculului nu va fi luată în\nconsiderare pentru opririle de încărcare planificate pe parcursul navigaţiei.", ru_RU="Верхний предел зарядки, установленный в меню автомобиля, не учитывается\nдля запланированных пунктов зарядки в рамках навигации.", sk_SK="Nastavená horná hranica nabíjania v ponuke vozidla sa pre naplánované zastávky\nnabíjania v rámci navigácie nezohľadňuje.", sl_SI="Nastavljena zgornja meja napolnjenosti v meniju vozila ne bo upoštevana pri\nnačrtovanih postankih za polnjenje v navigaciji.", sr_RS="Podešena gornja granica punjenja u meniju vozila se ne uzima u obzir za planirana\nzaustavljanja zbog punjenja u okviru navigacije.", sv_SE="De planerade laddstoppen i navigationsappen har inte tagit hänsyn till den övre\ninställda laddgränsen i fordonsmenyn.", tr_TR="Navigasyon içinde planlanan şarj durakları için araç menüsünde ayarlanan şarj üst\nsınırı dikkate alınmaz.", uk_UA="Верхня межа заряджання, встановлена в меню автомобіля, не враховується для\nзапланованих пунктів заряджання в рамках навігації.")
texttool_globals_dialog_message___google_search_result_explanation_content = TextObject(bs_BA="Kada pretražujete preduzeća ili mjesta u blizini određene lokacije, na Google\nmapama se prikazuju lokalni rezultati pretrage. Više faktora – prije svega\nrelevantnost, udaljenost, poznatost – se kombinuje za pronalaženje najboljih\nrezultata za Vašu pretragu.", cs_CZ="Při vyhledávání podniků nebo míst v blízkosti určitého místa zobrazují Google Maps\nvýsledky místního vyhledávání. Při vyhledání nejlepších výsledků se kombinuje\nněkolik faktorů – zejména relevance, vzdálenost a známost.", da_DK="Hvis du søger efter virksomheder eller steder i nærheden af en position, vises der\nlokale søgeresultater i Google Maps. Flere faktorer - frem for alt relevans, afstand,\nkendskabsgrad - kombineres for at finde frem til de bedste resultater for din\nsøgning.", de_DE="Wenn du nach Unternehmen oder Orten in der Nähe eines Standorts suchst,\nwerden in Google Maps lokale Suchergebnisse angezeigt. Mehrere Faktoren – vor\nallem Relevanz, Entfernung, Bekanntheit – werden kombiniert, um die besten\nErgebnisse für deine Suche zu finden.", el_GR="Όταν αναζητάτε επιχειρήσεις ή μέρη κοντά σε μια τοποθεσία, στο Google Maps\nεμφανίζονται τοπικά αποτελέσματα αναζήτησης. Πολλαπλοί παράγοντες – κυρίως η\nσυνάφεια, η απόσταση και η αναγνωρισιμότητα – συνδυάζονται για να βρεθούν τα\nκαλύτερα αποτελέσματα για την αναζήτησή σας.", en_GB="If you search for companies or places near a location, local search results will be\nshown in Google Maps. Multiple factors – primarily relevance, distance and\nprominence – are combined to find the best results for your search.", es_ES="Si busca empresas o lugares cerca de una ubicación, en Google Maps se mostrarán\nresultados de búsqueda locales. Se combinan varios factores (sobre todo\nrelevancia, distancia y popularidad) para ofrecer los mejores resultados de su\nbúsqueda.", fi_FI="Kun haet tietyn sijainnin lähistöllä olevia yrityksiä tai paikkoja, Google Mapsissa\nnäytetään paikallisia hakutuloksia. Jotta saisit parhaat tulokset haullesi,\nyhdistelemme useita tekijöitä, joita ovat erityisesti relevanssi, etäisyys ja\ntunnettuus.", fr_FR="Lorsque vous recherchez des entreprises ou des lieux proches d'une position,\nGoogle Maps affiche les résultats de recherche locaux. Plusieurs facteurs,\nnotamment la pertinence, la distance et la notoriété, sont combinés pour trouver\nles meilleurs résultats pour votre recherche.", hr_HR="Ako tražite poduzeća ili naselja u blizini neke lokacije, tada se u aplikaciji Google\nMaps prikazuju lokalni rezultati pretrage. Kombinira se više faktora - prije svega\nrelevantnost, udaljenost i poznatost, kako bi se pronašli najbolji rezultati za vašu\npretragu.", hu_HU="Amikor egy tartózkodási helyhez közeli cégekre vagy helyekre keresel, a Google\nTérkép helyi keresési eredményeket jelenít meg. Több tényező - főképpen a\nfontossági besorolás, a távolság és az ismertség - kombinálásával lehet elérni a\nlegjobb találatokat a keresésedhez.", it_IT="Quando si cercano aziende o luoghi vicini a una località, in Google Maps vengono\nvisualizzati i risultati della ricerca locali. Diversi fattori – in particolare la rilevanza,\nla distanza e la popolarità – vengono combinati per trovare i risultati migliori per la\nricerca.", nl_NL="Wanneer je bedrijven of plaatsen in de buurt van een locatie zoekt, worden lokale\nzoekresultaten weergegeven in Google Maps. Verschillende factoren, met name\nrelevantie, afstand, populariteit, worden zo gecombineerd dat je de beste\nresultaten voor je zoekopdracht krijgt.", no_NO="Når du søker etter bedrifter eller steder i nærheten av en posisjon, viser Google\nMaps lokale søkeresultater. Flere faktorer (bl.a. relevans, avstand og popularitet)\nkombineres for å gi de beste søkeresultatene.", pl_PL="Podczas wyszukiwania firm lub miejsc w pobliżu lokalizacji Mapy Google\nwyświetlają lokalne wyniki wyszukiwania. Kilka czynników – w szczególności\ntrafność, odległość, znajomość – jest łączonych w celu znalezienia najlepszych\nwyników wyszukiwania.", pt_PT="Quando procuras empresas ou locais nas imediações de uma localização, o Google\nMaps apresenta resultados da pesquisa locais. São combinados vários fatores,\nespecialmente, a importância, a distância, a familiaridade, para encontrar os\nmelhores resultados para a tua pesquisa.", ro_RO="În cazul în care căutaţi firme sau locuri în apropierea unei locaţii, se afişează în\nGoogle Maps rezultate locale pentru căutare. Se combină mai mulţi factori - mai\nales relevanţa, distanţa şi notorietatea - pentru a găsi cele mai bune rezultate\npentru căutarea dumneavoastră.", ru_RU="Когда вы ищете предприятия или места, расположенные поблизости, Google\nMaps отображает результаты локального поиска. Несколько факторов - в\nчастности, актуальность, расстояние, узнаваемость - объединяются, чтобы найти\nлучшие результаты для вашего поиска.", sk_SK="Ak hľadáte podniky alebo miesta v blízkosti určitého stanovišťa, v Google Maps sa\nzobrazia lokálne výsledky vyhľadávania. Kombinujú sa viaceré faktory – najmä\nrelevantnosť, vzdialenosť a známosť – aby sa našli najlepšie výsledky pre vaše\nvyhľadávanie.", sl_SI="Če iščete podjetja ali kraje v bližini lokacije, se v aplikaciji Google Zemljevidi\nprikažejo lokalni rezultati iskanja. Za najboljše rezultate iskanja je združenih več\ndejavnikov – predvsem ustreznost, oddaljenost in poznanost.", sr_RS="Ako tražite preduzeća ili mesta koja se nalaze u blizini određene lokacije, onda se na\nGoogle mapama prikazuju lokalni rezultati pretraživanja. Više faktora – pre svega\nrelevantnost, udaljenost, poznatost – se kombinuje da bi se pronašli najbolji\nrezultati za vaše pretraživanje.", sv_SE="Om du söker efter företag eller platser i närheten av en ort visas lokala sökresultat i\nGoogle Maps. Flera faktorer – framför allt relevans, avstånd och bekanthet –\nkombineras för att hitta bästa möjliga resultat för din sökning.", tr_TR="Bir konumun yakınındaki işletmeleri veya yerleri aradığında, Google Haritalarda\nyerel arama sonuçları gösterilir. Araman için en iyi sonuçları bulmak üzere çeşitli\nfaktörler – başta alaka, mesafe, popülerlik – birleştirilir.", uk_UA="Коли ви шукаєте підприємства або місця поблизу певного місця, Google Maps\nпоказують локальні результати пошуку. Кілька факторів - особливо\nрелевантність, відстань, популярність - поєднуються, щоб знайти найкращі\nрезультати для вашого пошуку.")
texttool_globals_dialog_message___house_number_disambiguation_content = TextObject(bs_BA="Unešeni broj kuće nije pronađen.", cs_CZ="Zadané číslo domu nebylo možné nalézt.", da_DK="Det angivne husnummer blev ikke fundet.", de_DE="Die eingegebene Hausnummer konnte nicht gefunden werden.", el_GR="Δεν ήταν εφικτή η εύρεση του αριθμού οικίας που καταχωρίστηκε.", en_GB="The house number entered could not be found.", es_ES="El número de casa introducido no se ha podido encontrar.", fi_FI="Syötettyä katunumeroa ei löytynyt.", fr_FR="Le numéro de maison entré n'a pas été trouvé.", hr_HR="Uneseni kućni broj nije pronađen.", hu_HU="A megadott házszámot nem sikerült megtalálni.", it_IT="Non è stato possibile trovare il numero civico immesso.", nl_NL="Het ingegeven huisnummer is niet gevonden.", no_NO="Finner ikke angitt husnummer.", pl_PL="Nie można znaleźć podanego numeru domu.", pt_PT="O número da porta introduzido não foi encontrado.", ro_RO="Numărul de casă introdus nu a putut fi găsit.", ru_RU="Введенный номер дома найти не удалось.", sk_SK="Uvedené číslo domu nie je možné nájsť.", sl_SI="Vnešene hišne številke ni bilo mogoče najti.", sr_RS="Nije bilo moguće pronaći uneti kućni broj.", sv_SE="Det angivna gatunumret kunde inte hittas.", tr_TR="Girilen kapı numarası bulunamadı.", uk_UA="Не вдалося знайти будинок з указаним номером.")
texttool_globals_dialog_message___no_phone_permission_popup_body = TextObject(bs_BA="Da biste dobili pristup povezanom telefonu, dodijelite neophodno ovlaštenje.", cs_CZ="Udělte potřebné oprávnění pro přístup k připojenému telefonu.", da_DK="Tildel den nødvendige autorisation for at få adgang til den forbundne telefon.", de_DE="Bitte erteile die notwendige Berechtigung, um Zugriff auf das verbundene Telefon\nzu erhalten.", el_GR="Χορηγήστε την απαραίτητη εξουσιοδότηση, για να αποκτήσετε πρόσβαση στο\nσυνδεδεμένο τηλέφωνο.", en_GB="Please provide the required permissions to access the connected telephone.", es_ES="Por favor, conceda el permiso necesario para acceder al teléfono conectado.", fi_FI="Myönnä tarvittava oikeus säilyttääksesi pääsyn yhdistettyyn puhelimeen.", fr_FR="Veuillez accorder les autorisations requises pour accéder au téléphone connecté.", hr_HR="Dodijelite potrebno odobrenje kako biste pristupili spojenom telefonu.", hu_HU="Add meg a szükséges engedélyt a csatlakoztatott telefonhoz való hozzáféréshez.", it_IT="Concedere l'autorizzazione necessaria per accedere al telefono collegato.", nl_NL="Geef de vereiste toestemming om toegang tot de verbonden telefoon te krijgen.", no_NO="Gi nødvendig tillatelse for å få tilgang til telefonen med forbindelse.", pl_PL="Proszę przydzielić wymagane uprawnienie, aby uzyskać dostęp do podłączonego\ntelefonu.", pt_PT="Por favor, concede a necessária permissão para obter acesso ao telefone ligado.", ro_RO="Acordaţi permisiunea necesară, pentru a obţine accesul la telefonul conectat.", ru_RU="Предоставьте необходимые полномочия для получения доступа к\nподключенному телефону.", sk_SK="Prosím, udeľte potrebné oprávnenie na získanie prístupu k pripojenému telefónu.", sl_SI="Za dostop do povezanega telefona podelite potrebno pooblastilo.", sr_RS="Da biste dobili pristup povezanom telefonu, dodelite neophodno ovlašćenje.", sv_SE="Tilldela den behörighet som krävs föratt få åtkomst till den anslutna telefonen.", tr_TR="Lütfen bağlı telefona erişim sağlamak için gerekli izni ver.", uk_UA="Надайте необхідні повноваження для отримання доступу до підключеного\nтелефону.")
texttool_globals_dialog_message___no_phone_permission_popup_title = TextObject(bs_BA="Nedostajuće ovlaštenje", cs_CZ="Chybějící oprávnění", da_DK="Manglende autorisation", de_DE="Fehlende Berechtigung", el_GR="Απουσία εξουσιοδότησης", en_GB="No authorisation", es_ES="Falta permiso", fi_FI="Puuttuva oikeus", fr_FR="Autorisation manquante", hr_HR="Nedostajuće ovlaštenje", hu_HU="Hiányzó jogosultság", it_IT="Manca l'autorizzazione", nl_NL="Ontbrekende machtiging", no_NO="Ingen tilgang", pl_PL="Brak uprawnienia", pt_PT="Sem autorização", ro_RO="Lipsă drepturi", ru_RU="Разрешение отсутствует", sk_SK="Chýbajúce povolenie", sl_SI="Manjkajoče pooblastilo", sr_RS="Nedostajuće ovlašćenje", sv_SE="Behörighet saknas", tr_TR="Yetki eksik", uk_UA="Немає дозволу")
texttool_globals_dialog_message___popup_charging_adapter_advertisement_text = TextObject(bs_BA="e-tron planer ruta može sada uvezati stanice za punjenje s NACS utikačima. Za\nnjihovo korištenje Vam je potreban adapter. Posjedujete NACS adapter za punjenje i\nželite koristiti NACS stanice za punjenje? U tom slučaju to možete podesiti u\npostavkama.", cs_CZ="Plánovač tras e-tron nyní dokáže integrovat nabíjecí stanice se zástrčkami NACS. K\njejich použití potřebujete adaptér. Máte nabíjecí adaptér NACS a chcete používat\nnabíjecí stanice NACS? Pak to můžete upravit v nastavení.", da_DK="e-tron-ruteplanneren kan nu integrere ladestationer med NACS-stik. For at anvende\ndem skal du bruge en adapter. Har du en NACS-ladeadapter, og vil du anvende\nNACS-ladestationer? Så kan du tilpasse dette i indstillingerne.", de_DE="Der e-tron Routenplaner kann jetzt Ladestationen mit NACS-Steckern einbinden.\nUm sie zu verwenden, benötigst du einen Adapter. Besitzt du einen\nNACS-Ladeadapter und möchtest NACS-Ladestationen nutzen? Dann kannst du dies\nin den Einstellungen anpassen.", el_GR="Ο σχεδιαστής διαδρομής e-tron μπορεί τώρα να ενσωματώσει σταθμούς φόρτισης με\nφις NACS. Για να τους χρησιμοποιήσετε, χρειάζεστε έναν αντάπτορα. Έχετε έναν\nαντάπτορα φόρτισης NACS και θέλετε να χρησιμοποιήσετε σταθμούς φόρτισης NACS;\nΤότε μπορείτε αυτό να το προσαρμόσετε στις ρυθμίσεις.", en_GB="The e-tron route planner can now incorporate charging stations with NACS\nconnectors. To use these, you require an adapter. Do you have an NACS charging\nadapter and want to use NACS charging stations? If so, you can modify this in the\nsettings.", es_ES="El planificador de rutas e-tron ahora puede incluir estaciones de carga con\nconectores NACS. Para utilizarlas, necesitará un adaptador. ¿Cuenta con un\nadaptador de carga NACS y desea utilizar estaciones de carga NACS? Entonces\npuede configurarlo en los ajustes.", fi_FI="e-tron-reittioppaaseen voi nyt sisällyttää latausasemia, joissa on NACS-pistoke.\nNiiden käyttöön tarvitaan sovitin. Onko sinulla NACS-lataussovitin ja haluat käyttää\nNACS-latausasemia? Voit määrittää tämän asetuksissa.", fr_FR="Le planificateur d'itinéraire e-tron peut désormais intégrer des bornes de recharge\navec connecteurs NACS. Pour les utiliser, vous avez besoin d'un adaptateur.\nDisposez-vous d'un adaptateur de recharge NACS et souhaitez-vous utiliser les\nbornes de recharge NACS? Vous pouvez alors modifier ceci dans les réglages.", hr_HR="e-tron planer ruta sada može obuhvatiti i stanice za punjenje s NACS utikačima.\nKako biste ih koristili, trebate adapter. Posjedujete li NACS adapter za punjenje i\nželite li koristiti NACS stanice za punjenje? Tada to možete prilagoditi u\npostavkama.", hu_HU="Mostantól az e-tron úvonaltervező fel tudja használni az NACS-csatlakozókkal\nellátott töltőállomásokat. A használatukhoz adapter szükséges. Van\nNACS-töltőadaptered és használni szeretnéd a NACS-töltőállomásokat? Ezt a\nbeállításokban módosíthatod.", it_IT="La pianificazione itinerario e-tron può ora integrare le stazioni di ricarica con\nconnettori NACS. Per utilizzarle è necessario un adattatore. Se si dispone di un\nadattatore di ricarica NACS e si desidera utilizzare le stazioni di ricarica NACS, è\npossibile configurarlo nelle impostazioni.", nl_NL="De e-tron routeplanner kan nu laadstations met NACS-stekkers integreren. Om ze\nte gebruiken, heb je een adapter nodig. Heb je een NACS-laadadapter en wil je\nNACS-laadstations gebruiken? Dan kun je dit aanpassen in de instellingen.", no_NO="e-tron-ruteplanleggeren kan nå inkludere ladestasjoner med NACS-støpsel. Du må\nha en adapter for å bruke dem. Har du en NACS-ladeadapter og vil bruke\nNACS-ladestasjoner? Da kan du stille inn det i innstillingene.", pl_PL="Planowanie trasy e-tron może teraz integrować stacje ładowania z wtykami NACS.\nAby z nich korzystać, potrzebny jest adapter. Czy masz adapter ładowania NACS i\nchcesz korzystać ze stacji ładowania NACS? Możesz to zmienić w ustawieniach.", pt_PT="O plano de trajeto e-tron pode agora ligar a estações de carregamento com fichas\nNACS. Para as utilizar necessitas de um adaptador. Tens um adaptador de\ncarregamento NACS e queres utilizar uma estação de carregamento NACS? Então\npodes realizar a adaptação nos ajustes.", ro_RO="Planificatorul de trasee e-tron poate include acum staţii de încărcare cu ştechere\nNACS. Pentru a le putea utiliza, aveţi nevoie de un adaptor. Dispuneţi de un adaptor\nde încărcare NACS şi doriţi să utilizaţi staţii de încărcare NACS? Atunci puteţi adapta\nacest lucru în setări.", ru_RU="Планировщик маршрута e-tron теперь может интегрировать зарядные станции\nсо штекерами NACS. Для их использования необходим адаптер. У вас есть\nадаптер для зарядки NACS и вы хотите использовать зарядные станции NACS?\nТогда вы можете настроить это в настройках.", sk_SK="Plánovač trasy e-tron teraz môže pripojiť nabíjacie stanice so zástrčkami NACS. Ak\nich chcete používať, potrebujete adaptér. Máte nabíjací adaptér NACS a chcete\npoužívať nabíjacie stanice NACS? Potom to môžete prispôsobiť v nastaveniach.", sl_SI="Načrtovalnik poti e-tron lahko zdaj upošteva polnilne postaje z vtiči NACS. Za\nnjihovo uporabo potrebujete adapter. Ali imate adapter za polnjenje NACS in želite\nuporabljati polnilne postaje NACS? Potem lahko to prilagodite v nastavitvah.", sr_RS="e-tron planer rute sada može da poveže stanice za punjenje sa NACS utikačima. Za\nnjihovo korišćenje vam je potreban adapter. Da li posedujete NACS adapter za\npunjenje i želite da koristite NACS stanice za punjenje? Onda to možete da\nprilagodite u podešavanjima.", sv_SE="e-tron ruttplanerare kan nu inkludera laddstationer med NACS-kontakter. För att\nkunna använda dem behöver du en adapter. Har du en NACS-laddadapter och vill\nanvända NACS-laddstationer? Då kan du ställa in detta i inställningarna.", tr_TR="E-tron rota planlayıcısı artık NACS fişlerine sahip şarj istasyonlarını entegre edebilir.\nBunları kullanabilmek için bir adaptöre ihtiyacın vardır. Bir NACS şarj adaptörün var\nmı ve NACS şarj istasyonlarını kullanmak istiyor musun? Daha sonra bunu\nayarlardan değiştirebilirsin.", uk_UA="Планувальник маршруту e-tron тепер може інтегрувати зарядні станції зі\nштекерами NACS. Для їх використання потрібен адаптер. У вас є адаптер для\nзаряджання NACS і ви хочете використовувати зарядні станції NACS? Тоді ви\nможете налаштувати це в налаштуваннях.")
texttool_globals_dialog_message___popup_charging_adapter_ccs_advertisement_text = TextObject(bs_BA="e-tron planer ruta sada može uključivati i stanice za punjenje s CCS utikačima. Za\nnjihovo korištenje Vam je potreban adapter. Posjedujete li CCS adapter za punjenje i\nželite koristiti CCS stanice za punjenje? Onda to možete prilagoditi u postavkama.", cs_CZ="Plánovač tras e-tron nyní dokáže integrovat nabíjecí stanice se zástrčkami CCS. K\njejich použití potřebujete adaptér. Máte nabíjecí adaptér CCS a chcete používat\nnabíjecí stanice CCS? Pak to můžete upravit v nastavení.", da_DK="e-tron-ruteplanneren kan nu integrere ladestationer med CCS-stik. For at anvende\ndem skal du bruge en adapter. Har du en CCS-ladeadapter, og vil du anvende\nCCS-ladestationer? Så kan du tilpasse dette i indstillingerne.", de_DE="Der e-tron Routenplaner kann jetzt Ladestationen mit CCS-Steckern einbinden. Um\nsie zu verwenden, benötigst du einen Adapter. Besitzt du einen CCS-Ladeadapter\nund möchtest CCS-Ladestationen nutzen? Dann kannst du dies in den Einstellungen\nanpassen.", el_GR="Ο σχεδιαστής διαδρομών e-tron έχει πλέον τη δυνατότητα να συμπεριλαμβάνει\nσταθμούς φόρτισης με φις τύπου CCS. Για να χρησιμοποιήσετε αυτά τα φις,\nχρειάζεστε έναν αντάπτορα. Έχετε αντάπτορα φόρτισης CCS και θέλετε να\nχρησιμοποιείτε σταθμούς φόρτισης CCS; Αυτό μπορείτε να το καθορίσετε στις\nρυθμίσεις.", en_GB="The e-tron route planner can now incorporate charging stations with CCS\nconnectors. An adapter is required to use these. If you have a CCS charging adapter\nand want to use CCS charging stations, you can select them in the settings.", es_ES="El planificador de rutas e-tron ahora puede incluir estaciones de carga con\nconectores CCS. Para utilizarlas, necesitará un adaptador. ¿Cuenta con un\nadaptador de carga CCS y desea utilizar estaciones de carga CCS? Entonces puede\nconfigurarlo en los ajustes.", fi_FI="e-tron-reittioppaaseen voi nyt sisällyttää latausasemia, joissa on CCS-pistoke.\nNiiden käyttöön tarvitaan sovitin. Onko sinulla CCS-lataussovitin ja haluat käyttää\nCCS-latausasemia? Voit määrittää tämän asetuksissa.", fr_FR="Le planificateur d'itinéraire e-tron peut désormais intégrer des bornes de recharge\navec connecteurs CCS. Pour les utiliser, vous avez besoin d'un adaptateur.\nDisposez-vous d'un adaptateur de recharge CCS et souhaitez-vous utiliser les\nbornes de recharge CCS? Vous pouvez alors modifier ceci dans les réglages.", hr_HR="e-tron planer ruta sada može uključiti i stanice za punjenje s CCS utikačem. Kako\nbiste ih koristili, potreban je adapter. Posjedujete li CCS adapter za punjenje i želite\nli koristiti CCS stanice za punjenje? Tada to možete prilagoditi u postavkama.", hu_HU="Az e-tron útvonaltervező mostantól képes integrálni a CCS-csatlakozókkal ellátott\ntöltőállomásokat. Ezek használatához adapterre van szükség. Van\nCCS-töltőadaptered, és szeretnéd használni a CCS-töltőállomásokat? Akkor ezt a\nbeállításokban állíthatod be.", it_IT="La pianificazione itinerario e-tron può ora includere le stazioni di ricarica con\nconnettori CCS. Per utilizzarle è necessario un adattatore. Se si dispone di un\nadattatore di ricarica CCS e si desidera utilizzare le stazioni di ricarica CCS, è\npossibile configurarlo nelle impostazioni.", nl_NL="De e-tron routeplanner kan nu laadstations met CCS-stekkers verwerken. Om deze\nte gebruiken, heb je een adapter nodig. Heb je een CCS-laadadapter en wil je\nCCS-laadstations gebruiken? Dan kun je dit in de instellingen aanpassen.", no_NO="e-tron-ruteplanleggeren kan nå inkludere ladestasjoner med CCS-støpsel. Du må ha\nen adapter for å bruke dem. Har du en CCS-ladeadapter og vil bruke\nCCS-ladestasjoner? Da kan du stille inn det i innstillingene.", pl_PL="Planowanie trasy e-tron może teraz integrować stacje ładowania z wtykami CCS.\nAby z nich korzystać, potrzebny jest adapter. Czy masz adapter ładowania CCS i\nchcesz korzystać ze stacji ładowania CCS? Możesz to zmienić w ustawieniach.", pt_PT="O planeamento de trajeto e-tron pode agora associar estações de carregamento\ncom fichas CCs. Para as utilizar necessita de um adaptador . Tens um adaptador de\ncarregamento CCS e queres utilizar estações de carregamento CCS? Então podes\nfaze-lo nos ajustes.", ro_RO="Planificatorul de trasee e-tron poate include acum staţii de încărcare cu ştechere\nCCS. Pentru a le putea utiliza, aveţi nevoie de un adaptor. Dispuneţi de un adaptor\nde încărcare CCS şi doriţi să utilizaţi staţii de încărcare CCS? Atunci puteţi adapta\nacest lucru în setări.", ru_RU="Планировщик маршрута e-tron теперь может интегрировать зарядные станции с\nразъемами CCS. Для их использования необходим адаптер. У вас есть адаптер\nдля зарядки CCS и вы хотите использовать зарядные станции CCS? Тогда вы\nможете настроить это в настройках.", sk_SK="Plánovač trasy e-tron teraz môže pripojiť nabíjacie stanice so zástrčkami CCS. Ak ich\nchcete používať, potrebujete adaptér. Máte nabíjací adaptér CCS a chcete používať\nnabíjacie stanice CCS? Potom to môžete prispôsobiť v nastaveniach.", sl_SI="Načrtovalnik poti e-tron lahko zdaj upošteva polnilne postaje z vtiči CCS. Za njihovo\nuporabo potrebujete adapter. Ali imate adapter za polnjenje CCS in želite\nuporabljati polnilne postaje CCS? Potem lahko to prilagodite v nastavitvah.", sr_RS="e-tron planer ruta sada može da uključi i stanice za punjenje sa CCS utikačima. Da\nbiste ih koristili, potreban vam je adapter. Posedujete li CCS adapter za punjenje i\nželite li koristiti CCS stanice za punjenje? Onda to možete da prilagodite u\npodešavanjima.", sv_SE="e-tron ruttplanerare kan nu inkludera laddstationer med CCS-uttag. För att kunna\nanvända dem behöver du en adapter. Har du en CCS-laddadapter och vill använda\nCCS-laddstationer? Då kan du ställa in detta i inställningarna.", tr_TR="E-tron rota planlayıcısı artık CCS fişlerine sahip şarj istasyonlarını entegre edebilir.\nBunları kullanabilmek için bir adaptöre ihtiyacın vardır. Bir CCS şarj adaptörün var\nmı ve CCS şarj istasyonlarını kullanmak istiyor musun? Daha sonra bunu ayarlardan\ndeğiştirebilirsin.", uk_UA="Планувальник маршрутів e-tron тепер може інтегрувати зарядні станції зі\nштекерами CCS. Для їх використання потрібен адаптер. У вас є адаптер для\nзарядки CCS і ви хочете використовувати зарядні станції CCS? Тоді ви можете\nналаштувати це в налаштуваннях.")
texttool_globals_dialog_message___popup_database_update_confirmation_message = TextObject(bs_BA="Upravo pokrećeš aktualizaciju mapa. Aktualizacija može trajati do otpr. 40 minuta. Tokom tog vremena možeš voziti, ali navigacija i pojedini sistemi asistencije vozaču neće biti raspoloživi tokom aktualizacije. Ostanite u vozilu dok se ne završi aktualizacija.", cs_CZ="Chystáte se spustit aktualizaci map. Aktualizace může trvat až cca 40 minut. Během této doby můžete řídit, ale navigace a některé asistenční systémy řidiče nebudou během aktualizace k dispozici. Zůstaňte prosím ve vozidle, dokud nebude aktualizace dokončena.", da_DK="Du er ved at starte en kortopdatering. Opdateringen kan vare op til 40 min. I dette tidsrum kan du køre i bilen, men navigationen og nogle førerassistentsystemer vil ikke være tilgængelige under opdateringen. Bliv i bilen, indtil opdateringen er afsluttet.", de_DE="Du bist dabei, ein Kartenupdate zu starten.\nDas Update kann bis zu ca. 40 Minuten dauern. In dieser Zeit kannst du fahren, aber\ndie Navigation und einige Fahrerasssistenzsysteme werden während des Updates\nnicht verfügbar sein. Bitte bleibe im Fahrzeug bis das Update abgeschlossen ist.", el_GR="Προτίθεστε να ξεκινήσετε μια αναβάθμιση χαρτών. Η αναβάθμιση μπορεί να διαρκέσει έως και περ. 40 λεπτά. Σε αυτό το χρονικό διάστημα μπορείτε να οδηγήσετε, αλλά η πλοήγηση και ορισμένα συστήματα υποβοήθησης οδηγού δεν θα είναι διαθέσιμα κατά τη διάρκεια της αναβάθμισης. Παραμείνετε μέσα στο όχημα, μέχρι να ολοκληρωθεί η αναβάθμιση.", en_GB="You are about to start a map update that can take up to 40 minutes. You can drive the vehicle during this time, but the navigation and driver assist systems are not available during the update. Please stay in the vehicle until the update is completed.", es_ES="Está a punto de iniciar una actualización de mapas. La actualización puede durar hasta 40 minutos aproximadamente. Mientras se realiza la actualización puede seguir conduciendo, pero la navegación y algunos sistemas de asistencia al conductor no estarán disponibles. Permanezca en el vehículo hasta que la actualización haya finalizado.", fi_FI="Olet käynnistämässä karttapäivityksen. Päivitys voi kestää noin 40 minuuttia. Sen aikana voit ajaa, mutta navigointi ja tietyt kuljettajaa avustavat järjestelmät eivät ole käytettävissä. Pysy autossa, kunnes päivitys on valmis.", fr_FR="Vous êtes sur le point de lancer une mise à jour de la carte. La mise à jour peut durer jusqu'à 40 minutes environ. Pendant la mise à jour, vous pourrez conduire, mais la navigation et certains systèmes d'assistance du conducteur ne seront pas disponibles. Veuillez rester dans le véhicule jusqu'à ce que la mise à jour soit terminée.", hr_HR="Pokrećete update kartografskog materijala. Update može trajati do cca. 40 minuta. U tom vremenu možete vozilti ali navigacija i neki sustavi potpora za vozača tijekom updatea neće biti raspoloživi. Ostanite u vozilu dok se update ne završi.", hu_HU="Térképfrissítés megkezdésére készülsz. A frissítés akár körülbelül 40 percig is eltarthat. Ez idő alatt vezethetsz, de a navigáció és egyes asszisztensrendszerek nem lesznek elérhetők. Maradj a járműben, amíg a frissítés be nem fejeződik.", it_IT="Si sta avviando un update delle cartine. L'update può richiedere fino a circa 40 minuti. Durante questo periodo è possibile guidare, ma la navigazione e alcuni sistemi di assistenza alla guida non saranno disponibili durante l'update. Si prega di rimanere nella vettura fino al completamento dell'update.", nl_NL="Je bent een kaartupdate aan het starten. De update kan tot ongeveer 40 minuten duren. In deze tijd kun je rijden, maar de navigatie en enkele bestuurdershulpsystemen zijn tijdens de update niet beschikbaar. Blijf in de auto tot de update is afgerond.", no_NO="Du er i ferd med å starte en kartoppdatering. Oppdateringen kan ta opptil 40 minutter. Du kan kjøre bilen i dette tidsrommet, men navigasjonssystemet og enkelte førerassistentsystemer er ikke tilgjengelige under oppdateringen. Du må bli værende i bilen til oppdateringen er ferdig.", pl_PL="Uruchamiasz aktualizację mapy. Aktualizacja może potrwać do około 40 minut. W tym czasie można jechać, ale nawigacja i niektóre systemy asysty kierowcy nie będą dostępne w trakcie aktualizacji. Należy pozostać w pojeździe do czasu zakończenia aktualizacji.", pt_PT="Estás prestes a iniciar uma atualização do mapa. A atualização pode durar até 40 minutos. Durante este período podes circular, mas a navegação e alguns sistemas de assistência à condução poderão não estar disponíveis durante a navegação. Por favor, permanece no veículo até a atualização estar concluída.", ro_RO="Tocmai iniţiaţi o actualizare de hărţi. Actualizarea poate dura până la circa 40 minute. În acest timp puteţi conduce, însă navigaţia şi unele sisteme de asistenţă a şoferului nu vor fi disponibile în timpul actualizării. Rămâneţi în autovehicul până la încheierea actualizării.", ru_RU="Вы собираетесь запустить обновление карт. Обновление может занять до 40 минут. В это время вы можете ехать, но навигация и некоторые системы помощи водителю будут недоступны во время обновления. Пожалуйста, оставайтесь в автомобиле, пока обновление не будет завершено.", sk_SK="Práve spúšťate aktualizáciu máp. Aktualizácia môže trvať približne 40 minút. Počas tejto doby môžete jazdiť, ale navigácia a niektoré asistenčné systémy vodiča nebudú dostupné. Prosím, zostaňte vo vozidle, kým sa aktualizácia nedokončí.", sl_SI="Zagnali boste posodobitev kartografskega gradiva. Posodobitev lahko traja do pribl. 40 minut. V tem času lahko vozite, vendar pa navigacija in nekateri asistenčni sistemi med posodobitvijo niso na voljo. Ostanite v vozilu, dokler posodobitev ni zaključena.", sr_RS="Upravo pokrećeš ažuriranje mapa. Ažuriranje može da traje do otpr. 40 minuta. Tokom tog vremena možeš da voziš, ali navigacija i pojedini sistemi asistencije vozaču neće biti dostupni tokom ažuriranja. Ostanite u vozilu dok se ne završi ažuriranje.", sv_SE="Du är på väg att starta en kartuppdatering. Uppdateringen kan ta upp till ca 40 minuter. Du kan köra under tiden, men navigationen och vissa förarassistanssystem är inte tillgängliga under uppdateringen. Stanna kvar i bilen tills uppdateringen är slutförd.", tr_TR="Bir harita güncellemesi başlatmak üzeresin. Güncelleme 40 dakikaya kadar sürebilir. Bu süre içinde sürüş yapabilirsi, ancak güncelleme sırasında navigasyon ve bazı sürücü destek sistemleri kullanılamaz. Lütfen güncelleme tamamlanana kadar araçta kal.", uk_UA="Ви починаєте оновлення карт. Оновлення може тривати до 40 хвилин. Протягом цього часу ви можете продовжувати рух, але навігація та деякі системи допомоги водієві будуть недоступні під час оновлення. Будь ласка, залишайтеся в автомобілі, доки оновлення не буде завершено.")
texttool_globals_dialog_message___popup_missing_contacts_permission = TextObject(bs_BA="Dodijelite ovlaštenje za %1 da biste mogli koristiti online funkcije.", cs_CZ="Udělte prosím oprávnění pro %1, abyste mohli využívat funkce online.", da_DK="Tildel beføjelse for %1 til at kunne anvende onlinefunktionerne.", de_DE="Bitte erteile die Berechtigung für %1, um die Online-Funktionen nutzen zu\nkönnen.", el_GR="Χορηγήστε το δικαίωμα για %1, για να μπορέσετε να χρησιμοποιήσετε τις\nonline λειτουργίες.", en_GB="Please give authorisation for %1 to use the online functions.", es_ES="Por favor, conceda el permiso para %1 y poder utilizar las funciones online.", fi_FI="Myönnä oikeus (%1) online-toimintojen käyttämistä varten.", fr_FR="Veuillez accorder votre autorisation à %1 pour pouvoir utiliser les fonctions\nen ligne.", hr_HR="Dodijelite ovlaštenje za %1 kako biste mogli koristiti online funkcije.", hu_HU="Kérünk, add meg a jogosultságot %1 számára az online funkciók\nhasználatához.", it_IT="Concedere l'autorizzazione per %1 per poter utilizzare le funzioni online.", nl_NL="Verleen de autorisatie voor %1 om de onlinefuncties te kunnen gebruiken.", no_NO="Du må gi %1 tillatelse til å bruke online-funksjonene.", pl_PL="Proszę przydzielić uprawnienie dla %1, aby móc korzystać z funkcji online.", pt_PT="Por favor, concede a permissão para %1 para poderes utilizar as funções\nonline.", ro_RO="Acordaţi drepturile pentru %1, pentru a putea utiliza funcţiile online.", ru_RU="Выдайте разрешение для %1, чтобы использовать онлайн-функции.", sk_SK="Prosím, udeľte oprávnenie pre %1, aby sa mohli využívať online funkcie.", sl_SI="Za uporabo spletnih funkcij podelite pooblastilo za %1.", sr_RS="Dodelite ovlašćenje za %1 da biste mogli koristiti onlajn funkcije.", sv_SE="Tilldela behörigheterna för %1 för att kunna använda onlinefunktionerna.", tr_TR="Lütfen %1 için, çevrimiçi özellikleri kullanabilmesine izin verin.", uk_UA="Надайте дозвіл для %1 для використання онлайнових функцій.")
texttool_globals_dialog_message___popup_modify_charging_time_confirm = TextObject(bs_BA="Preuzmi", cs_CZ="Převzít", da_DK="Overtag", de_DE="Übernehmen", el_GR="Υιοθέτηση", en_GB="Apply", es_ES="Utilizar", fi_FI="Ota käyttöön", fr_FR="Reprendre", hr_HR="Preuzeti", hu_HU="Átvétel", it_IT="Applica", nl_NL="Overnemen", no_NO="Overfør", pl_PL="Zastosuj", pt_PT="Assumir", ro_RO="Preluare", ru_RU="Принять", sk_SK="Prebrať", sl_SI="Prevzem", sr_RS="Preuzimanje", sv_SE="Spara", tr_TR="Devral", uk_UA="Застосувати")
